#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

int is_aligned(void *ptr, size_t alignment) {
    return ((uintptr_t)ptr % alignment) == 0;
}

int main(void) {
    {
        int *p = malloc(sizeof(int));
        printf("%d\n", (int)(is_aligned(p, 4)));
        free(p);
    }
    {
        int *p = malloc(sizeof(int));
        int result = is_aligned(p, 64);
        /* malloc typically gives 16-byte alignment on x86-64, not 64 */
        printf("%d\n", (p) != NULL ? 1 : 0);
        free(p);
    }
    {
        int *b = aligned_alloc(64, 64 * sizeof(int));
        printf("%d\n", (b) != NULL ? 1 : 0);
        printf("%d\n", (int)(is_aligned(b, 4)));
        printf("%d\n", (int)(is_aligned(b, 16)));
        printf("%d\n", (int)(is_aligned(b, 64)));
        free(b);
    }
    {
        int *b = aligned_alloc(64, 64 * sizeof(int));
        printf("%d\n", (b) != NULL ? 1 : 0);
        for (int i = 0; i < 8; i++) b[i] = i * i;
        printf("%d\n", (int)(b[0]));
        printf("%d\n", (int)(b[1]));
        printf("%d\n", (int)(b[7]));
        free(b);
    }
    return 0;
}

